	if (addr_len == 0) {
		if (len < 2)
			goto trunc;
 		ND_TCHECK(bp[1]);
 		switch (bp[0]) {
 		case 1:
 			af = AF_INET;
			addr_len = (u_int)sizeof(struct in_addr);
